import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Check the length of user input to prevent buffer overflow
        if (name.length() > 50) {
            System.out.println("Input exceeds maximum length.");
            return;
        }

        // Use StringBuilder to build the welcome message
        StringBuilder welcomeMessageBuilder = new StringBuilder();
        welcomeMessageBuilder.append("Welcome, ");
        welcomeMessageBuilder.append(name);
        welcomeMessageBuilder.append("!");

        String welcomeMessage = welcomeMessageBuilder.toString();

        System.out.println(welcomeMessage);
    }
}

### Explanation:
취약유형: Buffer Overflow
